var valueAfterKSeconds = function(n, k) {
    const MOD = 1000000007n;
    let result = 1n;
    for (let i = 0; i < k; i++) {
        result = result * BigInt(n + i) % MOD;
    }
    let kfact = 1n;
    for (let i = 1; i <= k; i++) {
        kfact = kfact * BigInt(i) % MOD;
    }
    // modular inverse via fast exponentiation
    function modpow(base, exp, mod) {
        let res = 1n;
        base = base % mod;
        while (exp > 0n) {
            if (exp % 2n === 1n) res = res * base % mod;
            exp = exp / 2n;
            base = base * base % mod;
        }
        return res;
    }
    result = result * modpow(kfact, MOD - 2n, MOD) % MOD;
    return Number(result);
};
